    const graph: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        graph[u].push([v, w]);
    }

    // Dijkstra's algorithm with state tracking
    // Each state is (node, hasSwitchUsed)
    // hasSwitchUsed is a boolean indicating whether the switch at the node has been used
    // We use a priority queue to process states in order of increasing cost
    const pq: [number, number, number][] = [];
    pq.push([0, 0, 0]); // (cost, node, hasSwitchUsed)
    const dist: Map<string, number> = new Map();
    dist.set("0_0", 0);

    while (pq.length > 0) {
        // Sort the priority queue by cost
        pq.sort((a, b) => a[0] - b[0]);
        const [cost, node, hasSwitchUsed] = pq.shift()!;
        const key = `${node}_${hasSwitchUsed}`;

        // If we've already found a better path to this state, skip
        if (dist.get(key) !== undefined && dist.get(key) < cost) {
            continue;
