        // If we reached the destination
        if (node === n - 1) {
            return cost;
        }

        // Explore neighbors
        for (const [v, w] of graph[node]) {
            // Regular edge
            const newCost = cost + w;
            const newKey = `${v}_0`;
            if (!dist.has(newKey) || dist.get(newKey) > newCost) {
                dist.set(newKey, newCost);
                pq.push([newCost, v, 0]);
