import "container/heap"

func solve(n int64, edges [][]int64) int64 {
    // Build the graph
    graph := make([][]struct{ v, w int64 }, n)
    for _, edge := range edges {
        u, v, w := edge[0], edge[1], edge[2]
        graph[u] = append(graph[u], struct{ v, w int64 }{v, w})
    }

    // Dijkstra's algorithm with state tracking
    // Each state is (cost, node, hasSwitchUsed)
    // hasSwitchUsed is a boolean indicating whether the switch at the node has been used
    type State struct {
        cost, node, hasSwitchUsed int64
    }
    pq := make(PriorityQueue, 1)
    pq[0] = State{0, 0, 0}
    heap.Init(&pq)

    // Map to track the minimum distance for each state
    dist := make(map[string]int64)
    dist["0_0"] = 0

    for pq.Len() > 0 {
        // Extract the state with the minimum cost
        state := heap.Pop(&pq).(State)
        cost, node, hasSwitchUsed := state.cost, state.node, state.hasSwitchUsed
        key := fmt.Sprintf("%d_%d", node, hasSwitchUsed)

        // If we've already found a better path to this state, skip
        if dist[key] < cost {
            continue
        }

        // If we reached the destination
        if node == n-1 {
            return cost
        }

        // Explore neighbors
        for _, edge := range graph[node] {
            v, w := edge.v, edge.w

            // Regular edge
            newCost := cost + w
            newKey := fmt.Sprintf("%d_0", v)
            if dist[newKey] > newCost {
                dist[newKey] = newCost
                heap.Push(&pq, State{newCost, v, 0})
            }

            // Reverse edge (if switch hasn't been used)
            if !hasSwitchUsed {
                reversedCost := cost + 2 * w
                reversedKey := fmt.Sprintf("%d_1", v)
                if dist[reversedKey] > reversedCost {
                    dist[reversedKey] = reversedCost
                    heap.Push(&pq, State{reversedCost, v, 1})
                }
            }
        }
    }

    // If we couldn't reach the destination
    return -1
}

type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool { return pq[i].cost < pq[j].cost }

func (pq PriorityQueue) Swap(i, j int) { pq[i], pq[j] = pq[j], pq[i] }

func (pq *PriorityQueue) Push(x interface{}) {
    item := x.(*State)
    *pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
    old := *pq
    n := len(old)
    item := old[n-1]
    *pq = old[0 : n-1]
    return item
}
